#include<bits/stdc++.h>
using namespace std;
vector<int> mp[1000010];
int fa[1000010][31],cnt[1000010],d[1000010],lg[1000010];
void dfs(int x,int f=0)
{
    fa[x][0]=f;
    d[x]=d[f]+1;
    for(int i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(int i:mp[x])
    {
        if(i!=f)
        {
            dfs(i,x);
        }
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
void dfs1(int x,int fa=-1)
{
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            dfs1(i,x);
            cnt[x]+=cnt[i];
        }
    }
}
void add(int x,int y)
{
    cnt[x]++;
    cnt[y]++;
    cnt[lca(x,y)]--;
    cnt[fa[lca(x,y)][0]]--;
}
int main()
{
    int n,a;
    scanf("%d%d",&n,&a);
    for(int i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(int i=1;i<n;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs(1);
    for(int i=1;i<=a;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        add(u,v);
    }
    dfs1(1);
    int u,v;
    scanf("%d%d",&u,&v);
    int l=lca(u,v);
    int ans=(cnt[l]==0);
    while(u!=l)
    {
        if(cnt[u]==0)
        {
            ans++;
        }
        u=fa[u][0];
    }
    while(v!=l)
    {
        if(cnt[v]==0)
        {
            ans++;
        }
        v=fa[v][0];
    }
    printf("%d",ans);
    return 0;
}
